/**
 * Generate OpenWeather firewall config.
 *
 * Data source: https://openweathermap.org/api
 *
 * OpenWeather authenticates with an API key passed as the `appid`
 * query parameter on every request.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://openweathermap.org/api";
// Format: 32 hex chars
const PLACEHOLDER_VALUE = "c0ffeesafelocal5afe10ca1c0ffeesa";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from OpenWeather API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:openweather",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const openweatherFirewall = {",
    '  name: "openweather",',
    '  description: "OpenWeather API",',
    "  placeholders: {",
    `    OPENWEATHER_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.openweathermap.org",',
    "      auth: {",
    "        query: {",
    '          appid: "${{ secrets.OPENWEATHER_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating OpenWeather firewall config...");
  const ts = generateTypeScript();
  writeOutput("openweather", ts, import.meta.dirname);
}
